module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output wire [15:0] result
);

reg [15:0] quotient;
reg [15:0] remainder;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        quotient <= 16'b0;
        remainder <= 16'b0;
        res_valid <= 1'b0;
    end else if (opn_valid && res_ready) begin
        if (sign) begin

            {quotient, remainder} <= dividend / divisor;
        end else begin

            {quotient, remainder} <= dividend / divisor;
        end
        res_valid <= 1'b1;
    end else begin
        res_valid <= 1'b0;
    end
end

assign result = {remainder, quotient};

endmodule
